css:
.loader {color: var(--loader-color, #4f46e5);
  --loader-secondary-color: #a5b4fc;
  --loader-bg: #ffffff;
   width: 70px;
   aspect-ratio: 1;
   --c: var(--loader-color, #4f46e5) 91%,#0000;
   background: radial-gradient(30% 50% at -3px 55%, var(--c)) top right, radial-gradient(30% 50% at -3px 45%, var(--c)) bottom right, radial-gradient(30% 50% at calc(100% + 3px) 55%, var(--c)) top left, radial-gradient(30% 50% at calc(100% + 3px) 45%, var(--c)) bottom left, radial-gradient(50% 30% at 45% calc(100% + 3px), var(--c)) top right, radial-gradient(50% 30% at 45% -3px , var(--c)) bottom right, radial-gradient(50% 30% at 55% calc(100% + 3px), var(--c)) top left, radial-gradient(50% 30% at 55% -3px , var(--c)) bottom left;
   background-size: 50.1% 50.1%;
   background-repeat: no-repeat;
   -webkit-mask: radial-gradient(circle 5px,#0000 90%,currentColor);
   animation: l8 1.5s infinite linear;
}
@keyframes l8  {
  100%{transform: rotate(1turn)}
}
